// Fetch all RSS feeds in a single node to avoid parallel branch execution
const feeds = [
  { name: 'TechCrunch', url: 'https://techcrunch.com/category/artificial-intelligence/feed/', type: 'rss' },
  { name: 'The Verge', url: 'https://www.theverge.com/rss/ai-artificial-intelligence/index.xml', type: 'rss' },
  { name: 'Ars Technica', url: 'https://feeds.arstechnica.com/arstechnica/index', type: 'rss' },
  { name: 'Google AI', url: 'https://blog.google/technology/ai/rss/', type: 'rss' },
  { name: 'OpenAI', url: 'https://openai.com/blog/rss.xml', type: 'rss' },
  { name: 'Anthropic', url: 'https://www.anthropic.com/rss.xml', type: 'rss' },
  { name: 'Hugging Face', url: 'https://huggingface.co/blog/feed.xml', type: 'rss' },
  { name: 'n8n', url: 'https://blog.n8n.io/rss/', type: 'rss' },
  { name: 'Twilio', url: 'https://www.twilio.com/blog/feed', type: 'rss' },
  { name: 'Import AI', url: 'https://importai.substack.com/feed', type: 'newsletter' },
  { name: 'Last Week in AI', url: 'https://lastweekin.ai/feed', type: 'newsletter' }
];

const maxPerFeed = $('Config').first().json.maxItemsPerFeed || 25;
const allItems = [];
const errors = [];

for (const feed of feeds) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      returnFullResponse: true,
      timeout: 15000,
    });

    const xml = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);

    // Simple RSS/Atom XML parsing
    const items = [];

    // Try RSS <item> tags first
    const rssItemRegex = /<item[\s>](.*?)<\/item>/gs;
    let match;
    while ((match = rssItemRegex.exec(xml)) !== null && items.length < maxPerFeed) {
      const itemXml = match[1];
      const title = (itemXml.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
      const link = (itemXml.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
      const pubDate = (itemXml.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
      const description = (itemXml.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';

      if (title || link) {
        items.push({
          json: {
            source: feed.name,
            type: feed.type || 'rss',
            title: title.replace(/<[^>]*>/g, '').trim(),
            url: link.trim(),
            publishedAt: pubDate ? new Date(pubDate).toISOString() : new Date().toISOString(),
            summary: description.replace(/<[^>]*>/g, '').substring(0, 300).trim()
          }
        });
      }
    }

    // If no RSS items found, try Atom <entry> tags
    if (items.length === 0) {
      const atomEntryRegex = /<entry[\s>](.*?)<\/entry>/gs;
      while ((match = atomEntryRegex.exec(xml)) !== null && items.length < maxPerFeed) {
        const entryXml = match[1];
        const title = (entryXml.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
        const link = (entryXml.match(/<link[^>]*href=["'](.*?)["']/s) || [])[1] || '';
        const published = (entryXml.match(/<(?:published|updated)[^>]*>(.*?)<\/(?:published|updated)>/s) || [])[1] || '';
        const summary = (entryXml.match(/<(?:summary|content)[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/(?:summary|content)>/s) || [])[1] || '';

        if (title || link) {
          items.push({
            json: {
              source: feed.name,
              type: feed.type || 'rss',
              title: title.replace(/<[^>]*>/g, '').trim(),
              url: link.trim(),
              publishedAt: published ? new Date(published).toISOString() : new Date().toISOString(),
              summary: summary.replace(/<[^>]*>/g, '').substring(0, 300).trim()
            }
          });
        }
      }
    }

    allItems.push(...items);
  } catch (err) {
    errors.push({ feed: feed.name, error: err.message || String(err) });
  }
}

// Log any feed errors as a system item
if (errors.length > 0) {
  allItems.push({
    json: {
      source: 'SYSTEM',
      title: `Feed errors: ${errors.map(e => e.feed).join(', ')}`,
      url: '',
      publishedAt: new Date().toISOString(),
      summary: errors.map(e => `${e.feed}: ${e.error}`).join('; ')
    }
  });
}

return allItems.length > 0
  ? allItems
  : [{ json: { source: 'SYSTEM', title: 'No items from any feed', url: '', publishedAt: new Date().toISOString(), summary: 'All feeds failed or returned empty.' } }];

// Merge & Normalize all feed items into standard format (preserves type: rss/newsletter)
const allItems = $input.all();
const maxTotal = $('Config').first().json.maxTotalItems || 150;
const normalized = [];

for (const item of allItems) {
  const d = item.json;
  if (!d.title && !d.url) continue;
  if (d.source === 'SYSTEM') {
    normalized.push(item);
    continue;
  }

  normalized.push({
    json: {
      source: d.source || 'Unknown',
      type: d.type || 'rss',
      title: (d.title || '').trim(),
      url: d.url || '',
      publishedAt: d.publishedAt || new Date().toISOString(),
      summary: (d.summary || '').replace(/<[^>]*>/g, '').substring(0, 300).trim()
    }
  });
}

normalized.sort((a, b) => new Date(b.json.publishedAt) - new Date(a.json.publishedAt));
const result = normalized.slice(0, maxTotal);

return result.length > 0
  ? result
  : [{ json: { source: 'SYSTEM', type: 'rss', title: 'No items found', url: '', publishedAt: new Date().toISOString(), summary: 'All feeds returned empty.' } }];

// Filter items to only those within the configured date window
const config = $('Config').first().json;
const days = config.dateWindowDays || 7;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - days);

const items = $input.all();
const filtered = items.filter(item => {
  const pubDate = new Date(item.json.publishedAt);
  return !isNaN(pubDate.getTime()) && pubDate >= cutoff;
});

return filtered.length > 0
  ? filtered
  : [{ json: { source: 'SYSTEM', title: 'No items in date window', url: '', publishedAt: new Date().toISOString(), summary: `No items found within last ${days} days.` } }];

// Dedupe using n8n workflow static data (30-day rolling window)
const items = $input.all();
const staticData = $getWorkflowStaticData('global');

// Initialize stores
if (!staticData.seenUrls) staticData.seenUrls = {};
if (!staticData.runHistory) staticData.runHistory = [];

// Clean entries older than 30 days
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
for (const [url, ts] of Object.entries(staticData.seenUrls)) {
  if (ts < thirtyDaysAgo) delete staticData.seenUrls[url];
}

const kept = [];
let seenCount = 0;

for (const item of items) {
  const url = item.json.url;
  if (!url || item.json.source === 'SYSTEM') {
    kept.push(item);
    continue;
  }

  if (staticData.seenUrls[url]) {
    seenCount++;
    continue;
  }

  staticData.seenUrls[url] = Date.now();
  kept.push(item);
}

// Store stats for run summary
staticData.lastRunStats = {
  totalIngested: items.length,
  seenCount,
  keptCount: kept.length,
  dedupeStoreSize: Object.keys(staticData.seenUrls).length
};

return kept.length > 0
  ? kept
  : [{ json: { source: 'SYSTEM', title: 'All items deduplicated', url: '', publishedAt: new Date().toISOString(), summary: `All ${items.length} items were already seen. seenCount=${seenCount}` } }];

// Build separate digests for RSS news and newsletter highlights
const items = $input.all();
const maxLength = $('Config').first().json.maxDigestChars || 12000;
const newsletterMaxLength = 4000;

let digest = '';
let newsletterDigest = '';
let truncated = false;
let newsletterTruncated = false;
let itemCount = 0;
let newsletterCount = 0;

for (const item of items) {
  const d = item.json;
  if (d.source === 'SYSTEM') continue;

  const entry = `[${d.source}] ${d.title}\n${d.url}\nPublished: ${d.publishedAt}\n${d.summary}\n\n---\n\n`;

  if (d.type === 'newsletter') {
    if (newsletterDigest.length + entry.length > newsletterMaxLength) {
      newsletterTruncated = true;
      continue;
    }
    newsletterDigest += entry;
    newsletterCount++;
  } else {
    if (digest.length + entry.length > maxLength) {
      truncated = true;
      continue;
    }
    digest += entry;
    itemCount++;
  }
}

if (truncated) digest += '\n[DIGEST TRUNCATED]\n';
if (newsletterTruncated) newsletterDigest += '\n[NEWSLETTER DIGEST TRUNCATED]\n';
if (itemCount === 0) digest = 'No new AI news items found this week.';
if (newsletterCount === 0) newsletterDigest = 'No newsletter items this week.';

return [{
  json: {
    digest,
    newsletterDigest,
    itemCount,
    newsletterCount,
    truncated,
    generatedAt: new Date().toISOString()
  }
}];

// Parse OpenAI response and extract the brief
const response = $json;
const briefContent = response.choices?.[0]?.message?.content || 'ERROR: No brief generated. Check OpenAI response.';
const usage = response.usage || {};
const itemCount = $('Prepare AI Request').first().json.itemCount || 0;

return [{
  json: {
    brief: briefContent,
    model: response.model || 'unknown',
    promptTokens: usage.prompt_tokens || 0,
    completionTokens: usage.completion_tokens || 0,
    totalTokens: usage.total_tokens || 0,
    itemCount
  }
}];

// Prepare Notion page creation body
const config = $('Config').first().json;
const brief = $('Parse AI Response').first().json.brief;
const today = new Date().toISOString().split('T')[0];

// Split brief into chunks of 2000 chars (Notion block limit)
const chunks = [];
for (let i = 0; i < brief.length; i += 2000) {
  chunks.push(brief.substring(i, i + 2000));
}

const children = chunks.map(chunk => ({
  object: 'block',
  type: 'paragraph',
  paragraph: {
    rich_text: [{ type: 'text', text: { content: chunk } }]
  }
}));

return [{
  json: {
    notionBody: {
      parent: { database_id: config.notionDatabaseId },
      properties: {
        Name: { title: [{ text: { content: `Weekly AI Brief — ${today}` } }] },
        Date: { date: { start: today } },
        Status: { select: { name: 'Published' } },
        Type: { select: { name: 'Weekly Brief' } }
      },
      children
    }
  }
}];

// Prepare Slack message body
const config = $('Config').first().json;
const brief = $('Parse AI Response').first().json.brief;
const today = new Date().toISOString().split('T')[0];

// Truncate if needed (Slack limit ~4000 chars per message)
let text = brief;
if (text.length > 3900) {
  text = text.substring(0, 3900) + '\n\n_[Brief truncated for Slack — see Notion for full version]_';
}

return [{
  json: {
    slackBody: {
      channel: config.slackChannelId,
      text: `*Weekly AI Brief — ${today}*\n\n${text}`,
      unfurl_links: false,
      unfurl_media: false
    }
  }
}];

// Build run summary with stats from all stages
const config = $('Config').first().json;
const staticData = $getWorkflowStaticData('global');
const dedupeStats = staticData.lastRunStats || {};
const aiResponse = $('Parse AI Response').first().json;

const summary = {
  tenantId: config.tenantId,
  runTimestamp: new Date().toISOString(),
  executionId: $execution?.id || 'unknown',
  itemCountIngested: dedupeStats.totalIngested || 0,
  itemCountAfterDateFilter: dedupeStats.totalIngested || 0,
  itemCountAfterDedupe: dedupeStats.keptCount || 0,
  seenCount: dedupeStats.seenCount || 0,
  dedupeStoreSize: dedupeStats.dedupeStoreSize || 0,
  digestItemCount: aiResponse.itemCount || 0,
  aiModel: aiResponse.model || 'unknown',
  aiTokensUsed: aiResponse.totalTokens || 0,
  notionEnabled: config.enableNotion,
  slackEnabled: config.enableSlack,
  sourcesUsed: ['TechCrunch', 'The Verge', 'Ars Technica', 'Google AI', 'OpenAI', 'Anthropic', 'Hugging Face', 'n8n', 'Twilio', 'Import AI', 'Last Week in AI']
};

// Store in static data for history
if (!staticData.runHistory) staticData.runHistory = [];
staticData.runHistory.push(summary);
// Keep last 52 runs (1 year of weekly runs)
if (staticData.runHistory.length > 52) {
  staticData.runHistory = staticData.runHistory.slice(-52);
}

return [{ json: summary }];
